import { eq, and, desc } from "drizzle-orm";
import { getDb } from "../db";
import { sessions } from "../db/schema";
import type { Session } from "@zcode/shared";
import crypto from "crypto";

function genId(): string {
  return crypto.randomUUID();
}

function now(): string {
  return new Date().toISOString();
}

function parseRow(row: Record<string, unknown>): Session {
  return {
    id: row.id as string,
    type: (row.type as string) as Session["type"],
    agent_name: row.agentName as string || (row as any).agent_name as string,
    task_id: row.taskId as string || (row as any).task_id as string,
    participants: JSON.parse((row.participants as string) || "[]"),
    status: (row.status as string) as Session["status"],
    parent_session_id: row.parentSessionId as string || (row as any).parent_session_id as string,
    max_rounds: row.maxRounds as number || (row as any).max_rounds as number,
    current_round: row.currentRound as number || (row as any).current_round as number,
    current_speaker: row.currentSpeaker as string || (row as any).current_speaker as string,
    artifacts: JSON.parse((row.artifacts as string) || "[]"),
    created_at: row.createdAt as string || (row as any).created_at as string,
    updated_at: row.updatedAt as string || (row as any).updated_at as string,
  } as Session;
}

export async function createSession(input: {
  id?: string;
  agentName: string;
  taskId: string;
  type?: string;
  status?: string;
  participants?: string[];
  maxRounds?: number;
  parentSessionId?: string;
  artifacts?: Record<string, unknown>[];
  boardId?: string;
  triggerMessageId?: string;
}): Promise<Session> {
  const db = getDb();
  const id = input.id || genId();
  const t = now();
  await db.insert(sessions).values({
    id,
    type: input.type || "main",
    agentName: input.agentName,
    taskId: input.taskId,
    participants: JSON.stringify(input.participants || []),
    status: input.status || "running",
    parentSessionId: input.parentSessionId || "",
    maxRounds: input.maxRounds || 50,
    currentRound: 0,
    currentSpeaker: "",
    artifacts: JSON.stringify(input.artifacts || []),
    boardId: input.boardId || "",
    triggerMessageId: input.triggerMessageId || "",
    createdAt: t,
    updatedAt: t,
  }).onConflictDoUpdate({
    target: sessions.id,
    set: {
      status: input.status || "running",
      artifacts: JSON.stringify(input.artifacts || []),
      updatedAt: t,
    },
  });
  return {
    id, type: (input.type || "main") as Session["type"],
    agent_name: input.agentName, task_id: input.taskId,
    participants: input.participants || [],
    status: (input.status || "running") as Session["status"],
    parent_session_id: input.parentSessionId || "",
    max_rounds: input.maxRounds || 50, current_round: 0,
    current_speaker: "",
    artifacts: (input.artifacts || []) as unknown as Session["artifacts"],
    created_at: t, updated_at: t,
  };
}

export async function getSession(id: string): Promise<Session | null> {
  const db = getDb();
  const rows = await db.select().from(sessions).where(eq(sessions.id, id));
  if (rows.length === 0) return null;
  return parseRow(rows[0]);
}

export async function updateSessionStatus(id: string, status: string): Promise<void> {
  const db = getDb();
  await db.update(sessions).set({ status, updatedAt: now() }).where(eq(sessions.id, id));
}

export async function listSessionsByTask(taskId: string): Promise<Session[]> {
  const db = getDb();
  const rows = await db.select().from(sessions)
    .where(eq(sessions.taskId, taskId))
    .orderBy(sessions.createdAt);
  return rows.map(parseRow);
}

export async function getMainSessionForTask(taskId: string): Promise<Session | null> {
  const db = getDb();
  const rows = await db.select().from(sessions)
    .where(and(eq(sessions.taskId, taskId), eq(sessions.type, "main")))
    .orderBy(desc(sessions.createdAt))
    .limit(1);
  if (rows.length === 0) return null;
  return parseRow(rows[0]);
}
