import { eq, desc } from "drizzle-orm";
import { getDb } from "../db";
import { projects } from "../db/schema";
import type { Project } from "@zcode/shared";
import crypto from "crypto";

function genId(): string {
  return crypto.randomBytes(4).toString("hex");
}

function now(): string {
  return new Date().toISOString();
}

function parseRow(row: Record<string, unknown>): Project {
  return {
    id: row.id as string,
    name: row.name as string,
    path: row.path as string,
    tech_stack: JSON.parse((row.techStack as string || (row as any).tech_stack as string) || "[]"),
    conventions: row.conventions as string,
    git_initialized: false,
    git_remote: "",
    created_at: row.createdAt as string || (row as any).created_at as string,
    updated_at: row.updatedAt as string || (row as any).updated_at as string,
  };
}

export async function createProject(input: {
  name: string;
  path?: string;
  gitRemote?: string;
}): Promise<Project> {
  const db = getDb();
  const id = genId();
  const t = now();
  await db.insert(projects).values({
    id,
    name: input.name,
    path: input.path ?? "",
    createdAt: t,
    updatedAt: t,
  });
  return {
    id, name: input.name, path: input.path ?? "",
    tech_stack: [], conventions: "",
    git_initialized: false, git_remote: input.gitRemote ?? "",
    created_at: t, updated_at: t,
  };
}

export async function listProjects(): Promise<Project[]> {
  const db = getDb();
  const rows = await db.select().from(projects).orderBy(desc(projects.updatedAt));
  return rows.map(parseRow);
}

export async function getProject(id: string): Promise<Project | null> {
  const db = getDb();
  const rows = await db.select().from(projects).where(eq(projects.id, id));
  if (rows.length === 0) return null;
  return parseRow(rows[0]);
}

export async function updateProject(
  id: string,
  input: { name?: string; path?: string; tech_stack?: string; conventions?: string },
): Promise<Project | null> {
  const existing = await getProject(id);
  if (!existing) return null;
  const db = getDb();
  const t = now();
  const techStack = input.tech_stack
    ? JSON.parse(input.tech_stack)
    : existing.tech_stack;
  await db.update(projects).set({
    name: input.name ?? existing.name,
    path: input.path ?? existing.path,
    techStack: JSON.stringify(techStack),
    conventions: input.conventions ?? existing.conventions,
    updatedAt: t,
  }).where(eq(projects.id, id));
  return getProject(id);
}

export async function deleteProject(id: string): Promise<boolean> {
  const db = getDb();
  const result = await db.delete(projects).where(eq(projects.id, id));
  const changes = (result as any).changes ?? (result as any).rowsAffected ?? 0;
  return changes > 0;
}
