import { eq, desc } from "drizzle-orm";
import { getDb } from "../db";
import { tasks } from "../db/schema";
import type { Task, TaskCreate, TaskUpdate } from "@zcode/shared";
import { eventHub } from "./events";
import { getAgentForStage } from "./pipeline";
import * as discussionSvc from "./discussion";
import crypto from "crypto";

function genId(): string {
  return crypto.randomBytes(4).toString("hex");
}

function now(): string {
  return new Date().toISOString();
}

function parseRow(row: Record<string, unknown>): Task {
  return {
    id: row.id as string,
    title: row.title as string,
    description: row.description as string,
    stage: row.stage as Task["stage"],
    status: row.status as Task["status"],
    artifacts: JSON.parse((row.artifacts as string) || "[]"),
    agent_name: row.agentName as string || (row as any).agent_name as string,
    conversation_id: row.conversationId as string || (row as any).conversation_id as string,
    project_id: row.projectId as string || (row as any).project_id as string,
    parent_task_id: row.parentTaskId as string || (row as any).parent_task_id as string,
    depends_on: JSON.parse((row.dependsOn as string || (row as any).depends_on as string) || "[]"),
    git_branch: row.gitBranch as string || (row as any).git_branch as string,
    created_at: row.createdAt as string || (row as any).created_at as string,
    updated_at: row.updatedAt as string || (row as any).updated_at as string,
  };
}

export async function createTask(input: TaskCreate): Promise<Task> {
  const db = getDb();
  const id = genId();
  const t = now();
  const stage = input.stage || "requirement";
  const dependsOn = input.depends_on ?? "[]";
  await db.insert(tasks).values({
    id,
    title: input.title,
    description: input.description ?? "",
    stage,
    status: "pending",
    parentTaskId: input.parent_task_id ?? "",
    dependsOn: typeof dependsOn === "string" ? dependsOn : JSON.stringify(dependsOn),
    createdAt: t,
    updatedAt: t,
  });
  const task: Task = {
    id, title: input.title, description: input.description ?? "",
    stage, status: "pending", artifacts: [],
    agent_name: "", conversation_id: "", project_id: "",
    parent_task_id: input.parent_task_id ?? "",
    depends_on: typeof dependsOn === "string" ? JSON.parse(dependsOn) : dependsOn,
    git_branch: "", created_at: t, updated_at: t,
  };
  eventHub.publish("task_updated", task);
  return task;
}

export async function listTasks(stage?: string): Promise<Task[]> {
  const db = getDb();
  const rows = stage
    ? db.select().from(tasks).where(eq(tasks.stage, stage)).orderBy(desc(tasks.updatedAt))
    : db.select().from(tasks).orderBy(desc(tasks.updatedAt));
  return (await rows).map(parseRow);
}

export async function getTask(id: string): Promise<Task | null> {
  const db = getDb();
  const rows = await db.select().from(tasks).where(eq(tasks.id, id));
  if (rows.length === 0) return null;
  return parseRow(rows[0]);
}

export async function updateTask(id: string, input: TaskUpdate): Promise<Task | null> {
  const existing = await getTask(id);
  if (!existing) return null;
  const db = getDb();
  const t = now();
  const artifacts = input.artifacts !== undefined
    ? JSON.parse(input.artifacts)
    : existing.artifacts;
  const dependsOn = input.depends_on !== undefined
    ? JSON.parse(input.depends_on)
    : existing.depends_on;
  await db.update(tasks).set({
    title: input.title ?? existing.title,
    description: input.description ?? existing.description,
    stage: input.stage ?? existing.stage,
    status: input.status ?? existing.status,
    artifacts: JSON.stringify(artifacts),
    agentName: input.agent_name ?? existing.agent_name,
    parentTaskId: input.parent_task_id ?? existing.parent_task_id,
    dependsOn: JSON.stringify(dependsOn),
    gitBranch: input.git_branch ?? existing.git_branch,
    updatedAt: t,
  }).where(eq(tasks.id, id));
  const updated: Task = {
    ...existing,
    title: input.title ?? existing.title,
    description: input.description ?? existing.description,
    stage: input.stage ?? existing.stage,
    status: input.status ?? existing.status,
    artifacts,
    agent_name: input.agent_name ?? existing.agent_name,
    parent_task_id: input.parent_task_id ?? existing.parent_task_id,
    depends_on: dependsOn,
    git_branch: input.git_branch ?? existing.git_branch,
    updated_at: t,
  };
  eventHub.publish("task_updated", updated);

  // Auto-add agent to discussion board when stage changes
  if (input.stage && input.stage !== existing.stage) {
    const agentName = getAgentForStage(input.stage);
    if (agentName) {
      try {
        const board = await discussionSvc.getBoardByTask(id);
        if (board) {
          await discussionSvc.addParticipant(board.id, agentName);
        }
      } catch { /* board may not exist yet */ }
    }
  }

  return updated;
}

export async function deleteTask(id: string): Promise<boolean> {
  const db = getDb();
  const result = await db.delete(tasks).where(eq(tasks.id, id));
  const changes = (result as any).changes ?? (result as any).rowsAffected ?? 0;
  if (changes > 0) {
    eventHub.publish("task_deleted", { id });
    return true;
  }
  return false;
}

export async function setTaskStatus(taskId: string, status: string): Promise<void> {
  await updateTask(taskId, { status: status as Task["status"] });
}
