import { Hono } from "hono";
import fs from "fs";
import path from "path";
import yaml from "js-yaml";

const agent = new Hono();

interface AgentConfig {
  name: string;
  role: string;
  stage: string;
  model: string;
  system_prompt: string;
}

interface AgentResponse {
  name: string;
  role: string;
  stage: string;
  model: string;
  description: string;
}

let agentCache: AgentResponse[] | null = null;

function loadAgents(): AgentResponse[] {
  if (agentCache) return agentCache;
  const agentsDir = path.resolve(process.env.AGENTS_DIR || "agents");
  if (!fs.existsSync(agentsDir)) return [];
  const dirs = fs.readdirSync(agentsDir).filter((d) =>
    fs.statSync(path.join(agentsDir, d)).isDirectory(),
  );
  agentCache = dirs.map((d) => {
    const cfgPath = path.join(agentsDir, d, "agent.yaml");
    const cfg: any = fs.existsSync(cfgPath)
      ? yaml.load(fs.readFileSync(cfgPath, "utf-8")) as any
      : {};
    return {
      name: cfg.name || d,
      role: cfg.role || "",
      stage: cfg.stage || "",
      model: cfg.model || "",
      description: cfg.role || cfg.name || d,
    };
  });
  return agentCache;
}

agent.get("/", (c) => c.json(loadAgents()));

agent.get("/reload", (c) => {
  agentCache = null;
  return c.json(loadAgents());
});

const STAGE_ORDER = ["requirement", "design", "development", "testing", "done"];

agent.get("/stages", (c) => {
  const agents = loadAgents().filter((a) => a.stage);
  const stageMap = new Map(agents.map((a) => [a.stage, a]));
  const result: { key: string; label: string; agent: string }[] = [];
  for (const key of STAGE_ORDER) {
    const a = stageMap.get(key);
    if (a) result.push({ key: a.stage, label: a.description, agent: a.name });
  }
  // Add any stages not in the fixed order
  for (const a of agents) {
    if (!STAGE_ORDER.includes(a.stage)) {
      result.push({ key: a.stage, label: a.description, agent: a.name });
    }
  }
  return c.json(result);
});

export default agent;
