import { eq, desc } from "drizzle-orm";
import { getDb } from "../db";
import { discussionBoards, discussionMessages } from "../db/schema";
import { eventHub } from "./events";
import * as sessionSvc from "./session";
import { SkillLoader } from "../engine/skill-loader";
import type {
  DiscussionBoard,
  DiscussionMessage,
  BoardMessageCreate,
  ProtocolCreate,
  Reaction,
} from "@zcode/shared";
import crypto from "crypto";

function genId(): string {
  return crypto.randomBytes(4).toString("hex");
}

function now(): string {
  return new Date().toISOString();
}

function parseBoard(row: Record<string, unknown>): DiscussionBoard {
  return {
    id: row.id as string,
    task_id: (row as any).task_id as string ?? row.taskId as string,
    participants: JSON.parse(
      ((row as any).participants as string ?? row.participants as string) || "[]"
    ),
    status: ((row as any).status as string ?? row.status as string) as DiscussionBoard["status"],
    created_at: ((row as any).created_at as string ?? row.createdAt as string) || "",
    updated_at: ((row as any).updated_at as string ?? row.updatedAt as string) || "",
  };
}

function parseMessage(row: Record<string, unknown>): DiscussionMessage {
  return {
    id: row.id as string,
    board_id: (row as any).board_id as string ?? row.boardId as string,
    speaker: row.speaker as string,
    content: row.content as string,
    trigger_type: ((row as any).trigger_type as string ?? row.triggerType as string) as DiscussionMessage["trigger_type"],
    mentions: JSON.parse(
      ((row as any).mentions as string ?? row.mentions as string) || "[]"
    ),
    topics: JSON.parse(
      ((row as any).topics as string ?? row.topics as string) || "[]"
    ),
    protocol_type: (((row as any).protocol_type ?? row.protocolType) as DiscussionMessage["protocol_type"]) ?? null,
    protocol_status: (((row as any).protocol_status ?? row.protocolStatus) as DiscussionMessage["protocol_status"]) ?? null,
    response_policy: (((row as any).response_policy ?? row.responsePolicy) as DiscussionMessage["response_policy"]) ?? null,
    reactions: JSON.parse(
      ((row as any).reactions as string ?? row.reactions as string) || "[]"
    ),
    parent_id: ((row as any).parent_id as string ?? row.parentId as string) || "",
    created_at: ((row as any).created_at as string ?? row.createdAt as string) || "",
  };
}

export async function getOrCreateBoard(taskId: string): Promise<DiscussionBoard> {
  const db = getDb();
  const rows = await db
    .select()
    .from(discussionBoards)
    .where(eq(discussionBoards.taskId, taskId));

  if (rows.length > 0) return parseBoard(rows[0]);

  const id = genId();
  const t = now();
  await db.insert(discussionBoards).values({
    id,
    taskId,
    participants: "[]",
    status: "active",
    createdAt: t,
    updatedAt: t,
  });
  return {
    id,
    task_id: taskId,
    participants: [],
    status: "active",
    created_at: t,
    updated_at: t,
  };
}

export async function getBoardByTask(taskId: string): Promise<DiscussionBoard | null> {
  const db = getDb();
  const rows = await db
    .select()
    .from(discussionBoards)
    .where(eq(discussionBoards.taskId, taskId));
  return rows.length > 0 ? parseBoard(rows[0]) : null;
}

export async function addParticipant(boardId: string, agentName: string): Promise<DiscussionBoard | null> {
  const db = getDb();
  const rows = await db
    .select()
    .from(discussionBoards)
    .where(eq(discussionBoards.id, boardId));
  if (rows.length === 0) return null;

  const board = parseBoard(rows[0]);
  if (board.participants.includes(agentName)) return board;

  const updated = [...board.participants, agentName];
  const t = now();
  await db
    .update(discussionBoards)
    .set({ participants: JSON.stringify(updated), updatedAt: t })
    .where(eq(discussionBoards.id, boardId));

  return { ...board, participants: updated, updated_at: t };
}

export async function listMessages(
  boardId: string,
  limit = 50,
  offset = 0,
): Promise<DiscussionMessage[]> {
  const db = getDb();
  const rows = await db
    .select()
    .from(discussionMessages)
    .where(eq(discussionMessages.boardId, boardId))
    .orderBy(desc(discussionMessages.createdAt))
    .limit(limit)
    .offset(offset);
  return rows.map(parseMessage).reverse();
}

export async function createMessage(
  boardId: string,
  input: BoardMessageCreate,
): Promise<DiscussionMessage> {
  const db = getDb();
  const id = genId();
  const t = now();

  await db.insert(discussionMessages).values({
    id,
    boardId,
    speaker: input.speaker,
    content: input.content,
    triggerType: input.trigger_type ?? "mention",
    mentions: JSON.stringify(input.mentions ?? []),
    topics: JSON.stringify(input.topics ?? []),
    protocolType: input.protocol_type ?? null,
    responsePolicy: input.response_policy ?? null,
    reactions: "[]",
    parentId: input.parent_id ?? "",
    createdAt: t,
  });

  // Auto-add mentioned agents as participants
  if (input.mentions && input.mentions.length > 0) {
    for (const name of input.mentions) {
      await addParticipant(boardId, name);
    }
  }
  // Add speaker as participant
  await addParticipant(boardId, input.speaker);

  const msg: DiscussionMessage = {
    id,
    board_id: boardId,
    speaker: input.speaker,
    content: input.content,
    trigger_type: input.trigger_type ?? "mention",
    mentions: input.mentions ?? [],
    topics: input.topics ?? [],
    protocol_type: input.protocol_type ?? null,
    protocol_status: null,
    response_policy: input.response_policy ?? null,
    reactions: [],
    parent_id: input.parent_id ?? "",
    created_at: t,
  };

  // Lookup taskId for event publishing
  const taskId = await lookupTaskId(boardId);
  publishBoardEvent(boardId, taskId, "board_message", `${input.speaker} 发送了消息`, { message: msg });

  // Trigger mini-sessions for @mentioned agents
  if (input.mentions && input.mentions.length > 0) {
    await triggerMentionSessions(boardId, taskId, id, input.mentions);
  }

  return msg;
}

export async function addReaction(
  messageId: string,
  reaction: Reaction,
): Promise<DiscussionMessage | null> {
  const db = getDb();
  const rows = await db
    .select()
    .from(discussionMessages)
    .where(eq(discussionMessages.id, messageId));
  if (rows.length === 0) return null;

  const msg = parseMessage(rows[0]);
  const reactions = [...msg.reactions, reaction];
  await db
    .update(discussionMessages)
    .set({ reactions: JSON.stringify(reactions) })
    .where(eq(discussionMessages.id, messageId));

  const updated = { ...msg, reactions };
  const taskId = await lookupTaskId(msg.board_id);
  publishBoardEvent(msg.board_id, taskId, "board_reaction", `${reaction.agent_name} ${reaction.action}`, { reaction });
  return updated;
}

export async function createProtocol(
  boardId: string,
  input: ProtocolCreate,
): Promise<DiscussionMessage> {
  const msg = await createMessage(boardId, {
    speaker: input.speaker,
    content: input.content,
    trigger_type: "protocol",
    mentions: input.mentions,
    protocol_type: input.protocol_type,
    response_policy: "must_follow_protocol",
  });

  // Set initial protocol status to pending
  const db = getDb();
  await db
    .update(discussionMessages)
    .set({ protocolStatus: "pending" })
    .where(eq(discussionMessages.id, msg.id));

  const taskId = await lookupTaskId(boardId);
  publishBoardEvent(boardId, taskId, "board_protocol_update", `${input.speaker} 发起了 ${input.protocol_type}`, {
    protocol_type: input.protocol_type,
    message_id: msg.id,
  });

  return { ...msg, protocol_status: "pending" };
}

export async function updateProtocolStatus(
  messageId: string,
  status: DiscussionMessage["protocol_status"],
): Promise<DiscussionMessage | null> {
  const db = getDb();
  const rows = await db
    .select()
    .from(discussionMessages)
    .where(eq(discussionMessages.id, messageId));
  if (rows.length === 0) return null;

  await db
    .update(discussionMessages)
    .set({ protocolStatus: status })
    .where(eq(discussionMessages.id, messageId));

  const msg = parseMessage(rows[0]);
  const taskId = await lookupTaskId(msg.board_id);
  publishBoardEvent(msg.board_id, taskId, "board_protocol_update", `协议状态变更为 ${status}`, {
    message_id: messageId,
    protocol_status: status,
  });
  return { ...msg, protocol_status: status };
}

function publishBoardEvent(
  boardId: string,
  taskId: string,
  event: string,
  summary: string,
  data?: Record<string, unknown>,
) {
  const payload = { type: event, board_id: boardId, task_id: taskId, ...data };
  eventHub.publish(`board:${boardId}`, payload);
  eventHub.publish("discussion_update", {
    type: "discussion_update",
    task_id: taskId,
    board_id: boardId,
    event,
    summary,
  });
}

async function lookupTaskId(boardId: string): Promise<string> {
  const db = getDb();
  const rows = await db.select().from(discussionBoards).where(eq(discussionBoards.id, boardId));
  return rows.length > 0 ? parseBoard(rows[0]).task_id : "";
}

export async function triggerMentionSessions(
  boardId: string,
  taskId: string,
  messageId: string,
  mentions: string[],
): Promise<void> {
  for (const agentName of mentions) {
    await sessionSvc.createSession({
      agentName,
      taskId,
      type: "discussion",
      boardId,
      triggerMessageId: messageId,
      maxRounds: 5,
    });
  }
}

export async function matchTopicsAndAddParticipants(
  boardId: string,
  content: string,
  excludeAgents: string[],
): Promise<string[]> {
  const loader = new SkillLoader();
  const matched: string[] = [];
  const lowerContent = content.toLowerCase();

  for (const agentName of loader.listAgents()) {
    if (excludeAgents.includes(agentName)) continue;
    const cfg = loader.getAgent(agentName);
    if (!cfg) continue;
    const topics = (cfg as any).discussion?.topics as string[] | undefined;
    if (!topics) continue;
    const isMatch = topics.some((t) => lowerContent.includes(t.toLowerCase()));
    if (isMatch) {
      await addParticipant(boardId, agentName);
      matched.push(agentName);
    }
  }
  return matched;
}
